// components/PostItem.js
import React, { useState } from 'react';
import CommentForm from './CommentForm';

function PostItem({ post, currentUser, onDelete, onUpdate, onLike, onComment }) {
  const [editing, setEditing] = useState(false);
  const [editedContent, setEditedContent] = useState(post.content);

  const handleUpdate = () => {
    onUpdate(post.id, editedContent);
    setEditing(false);
  };

  // 작성 시간 포맷 함수
  const formatDate = (isoString) => {
    const date = new Date(isoString);
    return date.toLocaleString('ko-KR', {
      year: 'numeric',
      month: 'long',
      day: 'numeric',
      hour: '2-digit',
      minute: '2-digit',
    });
  };

  return (
    <div style={{ border: '1px solid gray', padding: '10px', marginTop: '10px' }}>
      <p><strong>{post.author}</strong> 님의 게시글</p>
      <small>🕒 {formatDate(post.createdAt)}</small> {/* 🕒 작성 시간 표시 */}

      {editing ? (
        <>
          <textarea
            value={editedContent}
            onChange={(e) => setEditedContent(e.target.value)}
          />
          <button onClick={handleUpdate}>저장</button>
        </>
      ) : (
        <p>{post.content}</p>
      )}

      <p>
        공감: {post.likes}
        <button onClick={() => onLike(post.id)}>공감하기</button>
      </p>

      {post.author === currentUser && (
        <>
          <button onClick={() => setEditing(!editing)}>
            {editing ? '취소' : '수정'}
          </button>
          <button onClick={() => onDelete(post.id)}>삭제</button>
        </>
      )}

      {/* 댓글 */}
      <CommentForm onSubmit={(comment) => onComment(post.id, comment)} />
      <ul>
        {post.comments.map((c, i) => (
          <li key={i}>
            <strong>{c.user}:</strong> {c.content}
          </li>
        ))}
      </ul>
    </div>
  );
}

export default PostItem;
